abelDefinition": "税务部门采用年度评价指标得分和直接判级相结合的方式，依据纳税人信用历史信息、税务内部信息和外部信息等内容对纳税人进行信用评价，按照信用程度设为A、B、C、D四级，A级纳税人是税务部门评定的纳税信用级别最高的纳税人。", "labelName": "连续8年A级纳税人", "labelTranslateName": "公司诚信纳税"}, {"labelCode": "top500_priv_firms", "labelDefinition": "发布时间:2026-02-05,颁发机构:胡润研究院,评定年份:2025。由胡润研究院发布，按照企业市值或估值进行排名。这里“中国民营企业”是指总部在中国大陆的非公有制企业。如果是被母公司控股超过50%的公司，不单独上榜；母公司控股不超过50%的企业，若估值超过门槛，则单独上榜。", "labelName": "2025年胡润中国500强"}, {"labelCode": "top_nationwide", "labelDefinition": "据工商登记信息显示，该企业相比其他同行业更早进入市场。", "labelName": "经营年限全国同行前5%", "labelTranslateName": "行业内常青树"}, {"labelCode": "absolute_holding_companies", "labelDefinition": "该企业绝对控股15公司，绝对控股是指出资额占有限责任公司资本总额百分之六十七以上或者其持有的股份占股份有限公司股本总额百分之六十七以上。", "labelName": "绝对控股15家公司", "labelTranslateName": "强大经济实力公司"}, {"labelCode": "new_strategic_industry", "labelDefinition": "该企业申请、授权的专利属于以重大技术突破和重大发展需求为基础，对经济社会全局和长远发展具有重大引领带动作用，知识技术密集、物质资源消耗少、成长潜力大、综合效益好的战略性新兴产业。", "labelName": "战略性新兴领域创新能力", "labelTranslateName": "新兴领域创新企业"}, {"labelCode": "has_patent_high", "labelDefinition": "该企业拥有一项或多项高价值专利。高价值专利是指为专利权人带来高额收益或者竞争优势的专利。", "labelName": "拥有高价值专利"}, {"labelCode": "pat_grant_top_num", "labelDefinition": "据企业官方和专利局网站信息显示，该企业在武器领域获得的专利授权数量在同行业位于前列。", "labelName": "专利授权量同领域前50"}, {"labelCode": "tech_layout_leader", "labelDefinition": "该企业所采用的技术或技术路线已经或正在成为该行业的主流趋势，相比同行业具有较高的市场竞争力和创新能力。", "labelName": "技术布局行业领先"}, {"labelCode": "has_patent_green", "labelDefinition": "该企业拥有以绿色低碳技术为发明主题的专利。绿色低碳技术是指通过传统能源清洁利用、节能增效、新能源利用和温室气体捕集利用封存等实现减碳、零碳和负碳效果的有关技术。", "labelName": "拥有绿色低碳技术"}, {"labelCode": "ability_innovation", "labelDefinition": "根据企业公开的和国家专利局网站公示的专利信息显示，本企业拥有突出的工艺创新能力，在生产过程中，通过设计和实施新的生产工艺或改进现有工艺，实现生产效率和产品质量的提高，也降低了生产成本；同时也表明了本企业在技术水平、技术人才、创新发展等方面拥有较强的企业实力。", "labelName": "拥有工艺创新能力", "labelTranslateName": "工艺/技术创新能力突出"}, {"labelCode": "own_independent_brand", "labelDefinition": "该企业拥有高德红外、高德红外GuideIR自主品牌。", "labelName": "拥有自主品牌"}, {"labelCode": "college_employment_contribution", "labelDefinition": "据公开网络招聘信息显示，该企业在近1年内有发布过大学生就业岗位，助力大学生就业。", "labelName": "大学生就业贡献", "labelTranslateName": "欢迎应届生应聘"}], "showTypeUrl": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20250520/ptcard_128e85b893a640e8940c74c70daada54.png", "showTypeUrlDark": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20251208/a7401c7dc5b291eef900ff6b78327e18_f2a16bd811034ae78dea2e01b9945aee.png", "smallHrLogoUrl": "https://img01.51jobcdn.com/imehire/userportrait/default/li_portrait_female_005_small.png?v=20260317", "term": "0", "termStr": "全职", "triggerBatchDeliver": true, "updateDateTime": "2026-04-16 10:50:20", "userInteractionOnlineLabel": 2, "workAreaCode": "180200", "workYear": "6", "workYearString": "5年及以上"}

